using System;`n`nnamespace GestaoManutencao.Core.Domain`n{`n    public class ServicoRealizado`n    {`n        public string Descricao { get; private set; }`n        public double TempoGastoHoras { get; private set; }`n        public decimal ValorUnitario { get; private set; }`n        public decimal CustoTotal => (decimal)TempoGastoHoras * ValorUnitario;`n`n        public ServicoRealizado(string descricao, double tempoGastoHoras, decimal valorUnitario)`n        {`n            if (string.IsNullOrWhiteSpace(descricao))`n                throw new ArgumentException("Descricao do servico eh obrigatoria.");`n            if (tempoGastoHoras <= 0)`n                throw new ArgumentException("Tempo gasto deve ser maior que zero.");`n            if (valorUnitario < 0)`n                throw new ArgumentException("Valor unitario nao pode ser negativo.");`n`n            Descricao = descricao;`n            TempoGastoHoras = tempoGastoHoras;`n            ValorUnitario = valorUnitario;`n        }`n    }`n}
